INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-4c199b1b-moex-00022', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', 'S想把W欠他的20萬元借款債權打折賣給善於討債的H。下列敘述何者錯誤？', '["若債權有借條的話，S應把借條一起移轉給H", "若該債權有抵押權作為擔保，則抵押權原則上一併讓與給H", "S必須經過W的同意才能把債權賣給H", "若S或H把債權讓與告訴W，債權讓與對W就生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00023', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', 'W向S借款200萬元，S怕W不還錢，因此要求W把家裡的機車店面抵押給他，於是W的媽媽 把名下價值3,000萬元的機車店設定抵押權給S。下列敘述何者錯誤？', '["W的媽媽為抵押人、物上保證人", "W若到清償期還不還錢，S可以拍賣該抵押物，獲得優先清償", "若W的爸爸擔任保證人，則抵押權設定後，W的爸爸即可免其責任", "抵押權設定後，機車行仍由W一家人使用收益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00024', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', 'W 的阿公甲有塊地，甲對 W 說，「阿公在市區的那塊建地給你蓋房子，給不給錢都沒關係」，下 列那種土地的使用收益權利對W來說最有利？', '["地上權", "典權", "使用借貸", "租賃"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00025', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', 'S和W是夫妻，S雙親只剩下爸爸甲，W雙親只剩下媽媽乙，甲乙兩人因為S與W的關係認識， 雙方日久生情，想結婚。下列敘述何者正確？', '["可以，因甲乙雙方非姻親，無禁婚親問題", "可以，因為甲乙雙方雖為姻親，但非在禁婚親之列", "不可，因為雙方為禁婚親", "不可，因為雙方為直系姻親"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00026', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲有女兒乙、兒子丙，甲的先生早逝，甲含辛茹苦把乙丙兩人養大，但甲非常的重女輕男，要求 兒子丙在親朋好友的見證下，在甲的面前簽下拋棄繼承書。試問該拋棄繼承書的效力如何？', '["無效", "有效", "效力未定", "得撤銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00027', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲心血來潮，用電腦寫下遺囑，印表出來簽名交給朋友乙。下列敘述何者錯誤？', '["遺囑中甲寫到，曾和A女有婚外情，生B子，要B子認祖歸宗，該認領的意思表示無效", "甲的小孩丙偷看到該遺囑，氣炸，於是出手變造了遺囑內容，丙不因此喪失繼承權", "該遺囑不符合法定要式，無效", "即使是符合要式的遺囑，其中要子女兄友弟恭的內容，也沒有遺囑的效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00028', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'essay', '甲計劃在自己所有的 A地上興建B屋，遂與乙營造公司簽訂工程契約，
B屋建造完成後，甲發現因乙施作不當導致 A屋天花板漏水，遂憤而逕
依民法第495條第1項規定，請求損害賠償。試問甲之主張是否有理由？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00029', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'essay', '甲貨運公司所僱用的司機乙，於送貨途中闖紅燈，不慎撞死正在過馬路
的丙。丙遠在國外留學的未婚妻丁得知此消息後傷心欲絕，向乙請求慰
撫金，且由於丙生前全額負擔丁在國外之生活費，丁遂一併請求扶養費
之賠償，並依民法第 188 條規定，主張甲應負連帶賠償責任。試問丁之
主張是否有理由？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00030', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '有限合夥之性質為何？', '["財團法人", "社團法人", "非法人團體", "無權利能力社團"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00031', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-112-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '下列關於法律行為無效之敘述，依民法規定，何者正確？', '["法律行為之一部分無效者，僅該部分無效，其他部分，當然有效", "無效法律行為之當事人，於行為當時不知其無效，亦非可得而知者，負回復原狀或損害賠償之責任", "財團董事，有違反捐助章程之行為時，法院得因主管機關、檢察官或利害關係人之聲請，宣告其行為無效", "無效之法律行為，只要具備他法律行為之要件，不問當事人是否若知其無效，即欲為他法律行 為，均當然轉換為該他法律行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL)
